proof_block:
// The equal-fn `det_resolve_pagetable_mapping_equal` is phrased with the new
// pattern syntax (`r1 is Some`, `r1->Some_0`), while the ensures uses the
// deprecated method form (`r1.is_Some()`, `r1.unwrap()`). Bridge the two
// notations up front so z3 lines up the triggers across both forms.
assert((r1 is Some) == r1.is_Some());
assert((r1 is None) == r1.is_None());
assert((r2 is Some) == r2.is_Some());
assert((r2 is None) == r2.is_None());
assert(r1 is Some ==> r1->Some_0 == r1.unwrap());
assert(r2 is Some ==> r2->Some_0 == r2.unwrap());

// Anchor the shared mapping value so both ensures-conjuncts refer to the same
// instance (mapping_4k() is called four times in the ensures; let-binding it
// stabilises the trigger.)
let m = self_.get_pagetable_by_pcid(pcid).unwrap().mapping_4k();
assert(m == self_.get_pagetable_by_pcid(pcid).unwrap().mapping_4k());

// Case-split on the antecedent so z3 sees all four ensures-conjuncts (for r1
// and r2) as hypotheses in the same branch.
if (m.dom().contains(va) == r1.is_Some())
    && (r1.is_Some() ==>
        m.dom().contains(va)
            && m[va] == page_entry_to_map_entry(&r1.unwrap()))
    && (m.dom().contains(va) == r2.is_Some())
    && (r2.is_Some() ==>
        m.dom().contains(va)
            && m[va] == page_entry_to_map_entry(&r2.unwrap())) {

    // is_Some agrees on both sides via the same dom-containment witness.
    assert(m.dom().contains(va) == r1.is_Some());
    assert(m.dom().contains(va) == r2.is_Some());
    assert(r1.is_Some() == r2.is_Some());
    assert(r1.is_None() == r2.is_None());
    assert((r1 is Some) == (r2 is Some));
    assert((r1 is None) == (r2 is None));

    if r1 is Some {
        assert(r1.is_Some());
        assert(r2 is Some);
        assert(r2.is_Some());
        assert(m.dom().contains(va));

        // Bridge unwrap() and ->Some_0 so the two notations refer to the same
        // PageEntry instance.
        let e1: PageEntry = r1->Some_0;
        let e2: PageEntry = r2->Some_0;
        assert(e1 == r1.unwrap());
        assert(e2 == r2.unwrap());

        // Both PageEntrys map (via page_entry_to_map_entry) to the shared
        // m[va] value, so their MapEntry projections are equal.
        assert(m[va] == page_entry_to_map_entry(&r1.unwrap()));
        assert(m[va] == page_entry_to_map_entry(&r2.unwrap()));
        assert(m[va] == page_entry_to_map_entry(&e1));
        assert(m[va] == page_entry_to_map_entry(&e2));
        assert(page_entry_to_map_entry(&e1) == page_entry_to_map_entry(&e2));

        // `page_entry_to_map_entry` is `when_used_as_spec(spec_page_entry_to_map_entry)`;
        // unfold both sides to the open spec fn so its body becomes visible.
        assert(page_entry_to_map_entry(&e1) == spec_page_entry_to_map_entry(&e1));
        assert(page_entry_to_map_entry(&e2) == spec_page_entry_to_map_entry(&e2));
        assert(spec_page_entry_to_map_entry(&e1) == spec_page_entry_to_map_entry(&e2));
        assert(spec_page_entry_to_map_entry(&e1) =~= spec_page_entry_to_map_entry(&e2));

        // Lift MapEntry equality to per-field equalities on the underlying PageEntry.
        lemma_p2m_eq_implies_addr_write_xd(e1, e2);
        assert(e1.addr == e2.addr);
        assert(e1.perm.write == e2.perm.write);
        assert(e1.perm.execute_disable == e2.perm.execute_disable);

        // Re-express the goal of `det_resolve_pagetable_mapping_equal` in terms of
        // `e1`/`e2` so z3 sees `(r1->Some_0).view() == (r2->Some_0).view()` as
        // `e1.view() == e2.view()`.
        assert(r1->Some_0 == e1);
        assert(r2->Some_0 == e2);
    } else {
        assert(r1 is None);
        assert(r2 is None);
        assert(r1.is_None());
        assert(r2.is_None());
        assert(!r1.is_Some());
        assert(!r2.is_Some());
    }
}

helper_lemmas:
// Helper lemma: equal MapEntry values (output of `spec_page_entry_to_map_entry`)
// pin down the underlying PageEntry's addr / perm.write / perm.execute_disable
// fields. This is just structural projection on the open spec fn body
// `MapEntry { addr: p.addr, write: p.perm.write, execute_disable: p.perm.execute_disable }`.
proof fn lemma_p2m_eq_implies_addr_write_xd(e1: PageEntry, e2: PageEntry)
    requires
        spec_page_entry_to_map_entry(&e1) == spec_page_entry_to_map_entry(&e2),
    ensures
        e1.addr == e2.addr,
        e1.perm.write == e2.perm.write,
        e1.perm.execute_disable == e2.perm.execute_disable,
{
    assert(spec_page_entry_to_map_entry(&e1).addr == e1.addr);
    assert(spec_page_entry_to_map_entry(&e2).addr == e2.addr);
    assert(spec_page_entry_to_map_entry(&e1).write == e1.perm.write);
    assert(spec_page_entry_to_map_entry(&e2).write == e2.perm.write);
    assert(spec_page_entry_to_map_entry(&e1).execute_disable == e1.perm.execute_disable);
    assert(spec_page_entry_to_map_entry(&e2).execute_disable == e2.perm.execute_disable);
}
